module RefModule(
    input clk,
    input in,
    input reset,
    output reg out
);     // State Encoding
    parameter A = 0, B = 1, C = 2, D = 3;
    reg [1:0] pipeline_reg, next;

    // State Transition Logic
    always @(*) begin
        case (pipeline_reg)
            A: next = in ? B : B;
            B: next = in ? B : B;
            C: next = in ? A : C;
            D: next = in ? C : B;
        endcase
    end

    // State Register with synchronous Reset
    always @(posedge clk) begin
        if (reset) pipeline_reg <= B;
        else pipeline_reg <= next;
    end

    // Output Logic
    always @(*) begin
        case (pipeline_reg)
            A: out = 1;
            B: out = 0;
            C: out = 1;
            D: out = 0;
        endcase
    end
endmodule
